import React, { Component } from 'react';
import './Btn.css';

class Btn extends Component {

    state = {
        title: "",
        link: ""
    };

    openWindow = () => {
        window.open(this.state.link, '_blank');
    };

    render() {
        return (
            <button className="Btn" onClick={this.openWindow}>
                <div className="Btn-title">{this.title}</div>
            </button>
        );
    }
}

export default Btn;
